type TplLocale = "en" | "zh" | "es" | "pt" | "fr" | "ja" | "de" | "ko" | "zh-Hant";
// templateCopy accessor: zh-Hant derives from zh via OpenCC; de is authored natively;
// ko has no templateCopy block yet → falls back to en (foundation phase).
function tlCopy(locale: TplLocale): (typeof templateCopy)["en"] {
  if (locale === "zh-Hant") return deepHantTpl(templateCopy.zh) as unknown as (typeof templateCopy)["en"];
  return (templateCopy[locale as keyof typeof templateCopy] ?? templateCopy.en) as unknown as (typeof templateCopy)["en"];
}

export function createPdfToolMetadata(config: PdfToolPageConfig): Metadata {
  const canonicalPath = config.canonicalPath ?? `/${config.slug}/`;
  const pageUrl = `${siteUrl}${canonicalPath}`;
  const title = config.title.replace(/\s*\|\s*DockDocs\s*$/u, "");

  return {
    title,
    description: config.description,
    keywords: config.keywords,
    alternates: {
      canonical: canonicalPath,
      languages: config.alternateLanguages,
    },
    openGraph: {
      title,
      description: config.description,
      url: pageUrl,
      siteName: "DockDocs",
      type: "website",
      images: [{ url: `${siteUrl}/opengraph-image`, width: 1200, height: 630, alt: "DockDocs — every tool you need for PDFs" }],
    },
    twitter: {
      card: "summary_large_image",
      title,
      description: config.description,
      images: [`${siteUrl}/opengraph-image`],
    },
    robots: {
      index: true,
      follow: true,
    },
  };
}

export function createPdfToolSchema(config: PdfToolPageConfig) {
  const canonicalPath = config.canonicalPath ?? `/${config.slug}/`;
  const pageUrl = `${siteUrl}${canonicalPath}`;
  const toolDate = toolDates[config.slug] ?? {};
  const schemaLocale = config.locale ?? "en";
  const schemaTr = (en: string, zh: string, es: string, pt: string, fr: string, ja: string): string =>
    schemaLocale === "zh-Hant"
      ? ccTpl(zh)
      : // de/ko have no authored schema copy → English fallback (GAP: de/ko schema strings).
        schemaLocale === "de" || schemaLocale === "ko"
        ? en
        : ({ en, zh, es, pt, fr, ja })[schemaLocale];

  return {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "WebPage",
        "@id": `${pageUrl}#webpage`,
        url: pageUrl,
        name: config.title,
        description: config.description,
        // Real git dates (omitted if unavailable — never fabricated).
        ...(toolDate.datePublished ? { datePublished: toolDate.datePublished } : {}),
        ...(toolDate.dateModified ? { dateModified: toolDate.dateModified } : {}),
        // IndexingLinks target en-only surfaces (/guides, /blog, /resources +
        // their items). Use canonical non-prefixed URLs — a /pt|es|fr tool page
        // must NOT link to /pt/guides/… etc. (those locale variants don't exist → 404).
        significantLink: getIndexingLinks(config).map((link) =>
          absoluteHref(link.href),
        ),
        isPartOf: {
          "@type": "WebSite",
          name: "DockDocs",
          url: siteUrl,
        },
        publisher: { "@type": "Organization", "@id": `${siteUrl}#org` },
        about: {
          "@id": `${pageUrl}#app`,
        },
        breadcrumb: {
          "@id": `${pageUrl}#breadcrumb`,
        },
      },
      {
        "@type": "WebApplication",
        "@id": `${pageUrl}#app`,
        name: config.schemaName,
        applicationCategory: "BusinessApplication",
        operatingSystem: "Web",
        url: pageUrl,
        description: config.description,
        featureList: config.keywords,
        brand: {
          "@type": "Brand",
          name: "DockDocs",
          slogan: schemaTr(
            "AI document platform for real file workflows",
            "面向真实文件工作流的 AI 文档平台",
            "Plataforma de documentos con IA para flujos de trabajo de archivos reales",
            "Plataforma de documentos com IA para fluxos de trabalho de arquivos reais",
            "Plateforme documentaire IA pour les vrais flux de travail sur fichiers",
            "実際のファイル業務のための AI ドキュメントプラットフォーム",
          ),
        },
        offers: {
          "@type": "Offer",
          price: "0",
          priceCurrency: "USD",
        },
      },
      {
        "@type": "HowTo",
        "@id": `${pageUrl}#howto`,
        name: schemaTr(
          `How to use ${config.appName}`,
          `如何使用 ${config.appName}`,
          `Cómo usar ${config.appName}`,
          `Como usar ${config.appName}`,
          `Comment utiliser ${config.appName}`,
          `${config.appName} の使い方`,
        ),
        description: config.workflowDescription,
        step: config.steps.map((step, index) => ({
          "@type": "HowToStep",
          position: index + 1,
          text: step,
        })),
      },
      {
        "@type": "FAQPage",
        "@id": `${pageUrl}#faq`,
        mainEntity: config.faq.map((faq) => ({
          "@type": "Question",
          name: faq.question,
          acceptedAnswer: {
            "@type": "Answer",
            text: faq.answer,
          },
        })),
      },
      {
        "@type": "BreadcrumbList",
        "@id": `${pageUrl}#breadcrumb`,
        itemListElement: [
          {
            "@type": "ListItem",
            position: 1,
            name: "DockDocs",
            item: siteUrl,
          },
          {
            "@type": "ListItem",
            position: 2,
            name: config.breadcrumbName,
            item: pageUrl,
          },
        ],
      },
    ],
  };
}

// Standalone JSON-LD script for tool pages that render a custom *Client.tsx
// instead of <PdfToolPage> (e.g. merge/split/images-to-pdf visual editors).
// Those custom render paths bypass createPdfToolSchema, so drop this in
// alongside the client to keep structured data (GEO) coverage complete.
export function ToolJsonLd({ config }: { config: PdfToolPageConfig }) {
  return (
    <script
      type="application/ld+json"
      dangerouslySetInnerHTML={{
        __html: JSON.stringify(createPdfToolSchema(config)),
      }}
    />
  );
}

