  "Word documents": "Word 文档",
  "Scanned PDFs": "扫描版 PDF",
  "Extracted text": "提取的文字",
  "JPG images": "JPG 图片",
  "PNG images": "PNG 图片",
  "PDF document": "PDF 文档",
  "TXT file": "TXT 文件",
  "Markdown (.md)": "Markdown (.md)",
  "Trimmed PDF": "精简后的 PDF",
  "Rotated PDF": "旋转后的 PDF",
  "Reordered PDF": "重排后的 PDF",
  "PDF + blank page": "PDF + 空白页",
  "Encrypted PDF": "加密 PDF",
